import type { Variants } from 'framer-motion'
import { ProfileCard } from './components/about/ProfileCard'
import { PhilosophyCard } from './components/about/PhilosophyCard'

const containerVariants: Variants = {
  hidden: { opacity: 0 },
  visible: {
    opacity: 1,
    transition: {
      staggerChildren: 0.2,
      delayChildren: 0.1,
    },
  },
}

